import { useState } from 'react';
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = 'https://aejnfgtttbenrnlmrsam.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImFlam5mZ3R0dGJlbnJubG1yc2FtIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ2Mzk5NTMsImV4cCI6MjA5MDIxNTk1M30.8fLf1gmgdtF3J0JaLX_LC73Jk15N451zAfiM6NuDXdU';
const supabase = createClient(supabaseUrl, supabaseKey);

const LW360_LOGO = 'data:image/jpeg;base64,';

export default function App() {
  const [step, setStep] = useState(1);
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [form, setForm] = useState({
    name: '', legal_name: '', entity_type: '', ein: '',
    primary_contact_name: '', primary_contact_email: '', primary_contact_phone: '', primary_contact_title: '',
    employee_count_total: '', pay_frequency: 'Biweekly', is_school_district: false, is_trs_district: false
  });

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setForm(prev => ({ ...prev, [name]: type === 'checkbox' ? checked : value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      const code = (form.name.replace(/[^a-zA-Z0-9]/g, '').substring(0, 10) + '26').toUpperCase();
      const { error } = await supabase.from('organizations').insert([{
        ...form, code, intake_code: code, pipeline_stage: 'Intake Received',
        employee_count_total: parseInt(form.employee_count_total) || null,
        intake_submitted_at: new Date().toISOString()
      }]);
      if (error) throw error;
      setSubmitted(true);
    } catch (err) {
      alert('Error submitting form: ' + err.message);
    } finally {
      setSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #1e3a5f 0%, #2d5a87 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px' }}>
        <div style={{ backgroundColor: 'white', borderRadius: '16px', padding: '48px', maxWidth: '500px', textAlign: 'center', boxShadow: '0 20px 60px rgba(0,0,0,0.3)' }}>
          <div style={{ width: '80px', height: '80px', backgroundColor: '#dcfce7', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 24px', fontSize: '40px' }}>✓</div>
          <h2 style={{ color: '#1e293b', marginBottom: '16px' }}>Thank You!</h2>
          <p style={{ color: '#64748b', marginBottom: '24px' }}>Your intake form has been submitted successfully. Our team will review your information and contact you within 1-2 business days.</p>
          <p style={{ color: '#64748b', fontSize: '14px' }}>Questions? Call us at <strong>(806) 799-1099</strong></p>
        </div>
      </div>
    );
  }

  const inputStyle = { width: '100%', padding: '12px 16px', border: '1px solid #d1d5db', borderRadius: '8px', fontSize: '16px', outline: 'none' };
  const labelStyle = { display: 'block', marginBottom: '6px', fontWeight: 500, color: '#374151', fontSize: '14px' };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #1e3a5f 0%, #2d5a87 100%)' }}>
      {/* Header */}
      <header style={{ padding: '24px', textAlign: 'center' }}>
        <img src={LW360_LOGO} alt="Live Well 360" style={{ height: '50px', marginBottom: '12px' }} />
        <h1 style={{ color: 'white', fontSize: '28px', fontWeight: 700, marginBottom: '8px' }}>Employer Intake Form</h1>
        <p style={{ color: '#7AC143', fontSize: '16px' }}>Let's get started with your wellness benefit program</p>
      </header>

      {/* Form */}
      <main style={{ maxWidth: '700px', margin: '0 auto', padding: '0 24px 48px' }}>
        <form onSubmit={handleSubmit} style={{ backgroundColor: 'white', borderRadius: '16px', padding: '32px', boxShadow: '0 20px 60px rgba(0,0,0,0.3)' }}>
          
          {/* Step 1: Company Info */}
          <div style={{ marginBottom: '32px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '20px' }}>
              <div style={{ width: '32px', height: '32px', borderRadius: '50%', backgroundColor: '#7AC143', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600 }}>1</div>
              <div><h3 style={{ color: '#1e293b', margin: 0 }}>Company Information</h3><p style={{ color: '#64748b', fontSize: '14px', margin: 0 }}>Tell us about your organization</p></div>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
              <div><label style={labelStyle}>Company Name *</label><input name="name" value={form.name} onChange={handleChange} required style={inputStyle} placeholder="e.g., Acme Corporation" /></div>
              <div><label style={labelStyle}>Legal Entity Name</label><input name="legal_name" value={form.legal_name} onChange={handleChange} style={inputStyle} placeholder="If different from company name" /></div>
              <div><label style={labelStyle}>Entity Type *</label>
                <select name="entity_type" value={form.entity_type} onChange={handleChange} required style={inputStyle}>
                  <option value="">Select entity type...</option>
                  <option value="LLC">LLC</option><option value="S-Corp">S-Corp</option><option value="C-Corp">C-Corp</option>
                  <option value="Partnership">Partnership</option><option value="Sole Prop">Sole Proprietorship</option>
                  <option value="School District">School District</option><option value="Government">Government</option><option value="Non-Profit">Non-Profit</option>
                </select>
              </div>
              <div><label style={labelStyle}>EIN</label><input name="ein" value={form.ein} onChange={handleChange} style={inputStyle} placeholder="XX-XXXXXXX" /></div>
            </div>
          </div>

          {/* Step 2: Contact Info */}
          <div style={{ marginBottom: '32px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '20px' }}>
              <div style={{ width: '32px', height: '32px', borderRadius: '50%', backgroundColor: '#29ABE2', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600 }}>2</div>
              <div><h3 style={{ color: '#1e293b', margin: 0 }}>Primary Contact</h3><p style={{ color: '#64748b', fontSize: '14px', margin: 0 }}>Who should we contact?</p></div>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
              <div><label style={labelStyle}>Contact Name *</label><input name="primary_contact_name" value={form.primary_contact_name} onChange={handleChange} required style={inputStyle} /></div>
              <div><label style={labelStyle}>Title</label><input name="primary_contact_title" value={form.primary_contact_title} onChange={handleChange} style={inputStyle} /></div>
              <div><label style={labelStyle}>Email *</label><input name="primary_contact_email" type="email" value={form.primary_contact_email} onChange={handleChange} required style={inputStyle} /></div>
              <div><label style={labelStyle}>Phone *</label><input name="primary_contact_phone" value={form.primary_contact_phone} onChange={handleChange} required style={inputStyle} /></div>
            </div>
          </div>

          {/* Step 3: Employee Info */}
          <div style={{ marginBottom: '32px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '20px' }}>
              <div style={{ width: '32px', height: '32px', borderRadius: '50%', backgroundColor: '#1e3a5f', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600 }}>3</div>
              <div><h3 style={{ color: '#1e293b', margin: 0 }}>Employee Information</h3><p style={{ color: '#64748b', fontSize: '14px', margin: 0 }}>Tell us about your workforce</p></div>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
              <div><label style={labelStyle}>Total Employees *</label><input name="employee_count_total" type="number" value={form.employee_count_total} onChange={handleChange} required style={inputStyle} /></div>
              <div><label style={labelStyle}>Pay Frequency *</label>
                <select name="pay_frequency" value={form.pay_frequency} onChange={handleChange} required style={inputStyle}>
                  <option value="Weekly">Weekly</option><option value="Biweekly">Biweekly</option>
                  <option value="Semi-Monthly">Semi-Monthly</option><option value="Monthly">Monthly</option>
                </select>
              </div>
            </div>
            <div style={{ marginTop: '16px', display: 'flex', gap: '24px' }}>
              <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' }}>
                <input type="checkbox" name="is_school_district" checked={form.is_school_district} onChange={handleChange} />
                <span style={{ fontSize: '14px', color: '#374151' }}>School District</span>
              </label>
              <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' }}>
                <input type="checkbox" name="is_trs_district" checked={form.is_trs_district} onChange={handleChange} />
                <span style={{ fontSize: '14px', color: '#374151' }}>TRS District (Texas)</span>
              </label>
            </div>
          </div>

          <button type="submit" disabled={submitting} style={{ width: '100%', padding: '16px', backgroundColor: '#7AC143', color: 'white', border: 'none', borderRadius: '8px', fontSize: '18px', fontWeight: 600, cursor: submitting ? 'not-allowed' : 'pointer', opacity: submitting ? 0.7 : 1 }}>
            {submitting ? 'Submitting...' : 'Submit Intake Form'}
          </button>
        </form>
      </main>
    </div>
  );
}
